import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { useLanguage } from '../contexts/LanguageContext';
import api from '../services/api';

// ─── COLOUR SYSTEM ─────────────────────────────────────────────────────────
// Red 0–10 WPM | Orange 10–30 WPM | Green 30–80 WPM (darkens at high end)
const R_END   = 10 / 80;
const G_START = 30 / 80;

function rog(pct) {
  const p = Math.max(0, Math.min(1, pct));
  if (p <= R_END) return 'rgb(220,38,38)';
  if (p <= G_START) {
    const t = (p - R_END) / (G_START - R_END);
    return `rgb(${Math.round(220+(249-220)*t)},${Math.round(38+(115-38)*t)},${Math.round(38+(22-38)*t)})`;
  }
  const t = (p - G_START) / (1 - G_START);
  const e = t * t * (3 - 2 * t);
  return `rgb(${Math.round(249+(22-249)*e)},${Math.round(115+(101-115)*e)},${Math.round(22+(52-22)*e)})`;
}

function rogSubtle(pct) {
  const p = Math.max(0, Math.min(1, pct));
  if (p <= R_END) return 'rgb(200,95,95)';
  if (p <= G_START) {
    const t = (p - R_END) / (G_START - R_END);
    return `rgb(${Math.round(200+(215-200)*t)},${Math.round(95+(155-95)*t)},${Math.round(95+(55-95)*t)})`;
  }
  const t = (p - G_START) / (1 - G_START);
  const e = t * t * (3 - 2 * t);
  return `rgb(${Math.round(215+(55-215)*e)},${Math.round(155+(135-155)*e)},${Math.round(55+(85-55)*e)})`;
}

// ─── SPEEDOMETER ────────────────────────────────────────────────────────────
function Speedometer({ wpm }) {
  const max = 80, pct = Math.min((wpm || 0) / max, 1);
  const size = 158, cx = size / 2, cy = size / 2, r = size * 0.37;

  function xy(a, rad) {
    const angle = (a - 90) * Math.PI / 180;
    return { x: cx + rad * Math.cos(angle), y: cy + rad * Math.sin(angle) };
  }
  function arc(a1, a2, rad) {
    const s = xy(a1, rad), e = xy(a2, rad);
    return `M ${s.x} ${s.y} A ${rad} ${rad} 0 ${a2 - a1 > 180 ? 1 : 0} 1 ${e.x} ${e.y}`;
  }

  const na       = -135 + pct * 270;
  const tip      = xy(na, r - 10);
  const b1       = xy(na + 90, 5);
  const b2       = xy(na - 90, 5);
  const redEnd   = -135 + R_END * 270;
  const greenSt  = -135 + G_START * 270;
  const cc       = rog(pct);

  return (
    <svg
      width={size}
      height={size * 0.76}
      viewBox={`0 0 ${size} ${size * 0.76}`}
      style={{ display: 'block', margin: '0 auto' }}
    >
      <defs>
        <linearGradient id="dash-sg" gradientUnits="userSpaceOnUse" x1="10" y1={cy} x2={size - 10} y2={cy}>
          <stop offset="0%"    stopColor="#dc2626" />
          <stop offset="12.4%" stopColor="#dc2626" />
          <stop offset="12.6%" stopColor="#f97316" />
          <stop offset="37.4%" stopColor="#f97316" />
          <stop offset="37.6%" stopColor="#22a34a" />
          <stop offset="70%"   stopColor="#166534" />
          <stop offset="100%"  stopColor="#134e2a" />
        </linearGradient>
        <filter id="dash-glow">
          <feGaussianBlur stdDeviation="2" result="b" />
          <feMerge><feMergeNode in="b" /><feMergeNode in="SourceGraphic" /></feMerge>
        </filter>
      </defs>

      {/* Track */}
      <path d={arc(-135, 135, r)} fill="none" stroke="#dbeafe" strokeWidth={11} strokeLinecap="round" />
      {/* Zone tints */}
      <path d={arc(-135, redEnd, r)}    fill="none" stroke="#dc2626" strokeWidth={11} strokeLinecap="butt" opacity={0.1} />
      <path d={arc(redEnd, greenSt, r)} fill="none" stroke="#f97316" strokeWidth={11} strokeLinecap="butt" opacity={0.1} />
      <path d={arc(greenSt, 135, r)}    fill="none" stroke="#166534" strokeWidth={11} strokeLinecap="butt" opacity={0.1} />
      {/* Filled arc */}
      <path d={arc(-135, na, r)} fill="none" stroke="url(#dash-sg)" strokeWidth={11} strokeLinecap="round" filter="url(#dash-glow)" />

      {/* Ticks every 10 WPM */}
      {[0, 10, 20, 30, 40, 50, 60, 70, 80].map(v => {
        const a     = -135 + (v / max) * 270;
        const major = [0, 10, 20, 30, 40, 60, 80].includes(v);
        const inn   = xy(a, r - (major ? 9 : 6));
        const out   = xy(a, r - 4);
        const lp    = xy(a, r - 18);
        return (
          <g key={v}>
            <line x1={inn.x} y1={inn.y} x2={out.x} y2={out.y}
              stroke={rog(v / max)} strokeWidth={major ? 2 : 1.2} strokeLinecap="round" opacity={0.7} />
            {major && (
              <text x={lp.x} y={lp.y + 3} textAnchor="middle" fill="#7aa8c0" fontSize={8}>{v}</text>
            )}
          </g>
        );
      })}

      {/* Zone boundary markers at 10 and 30 */}
      {[10, 30].map(v => {
        const a   = -135 + (v / max) * 270;
        const inn = xy(a, r - 22);
        const out = xy(a, r - 5);
        return (
          <line key={v} x1={inn.x} y1={inn.y} x2={out.x} y2={out.y}
            stroke={rog(v / max)} strokeWidth={2} strokeLinecap="round" opacity={0.65} />
        );
      })}

      {/* Needle */}
      <polygon points={`${tip.x},${tip.y} ${b1.x},${b1.y} ${b2.x},${b2.y}`} fill="#1e3a5f" opacity={0.8} />
      <circle cx={cx} cy={cy} r={7} fill="#fff" stroke={cc} strokeWidth={2} />
      <circle cx={cx} cy={cy} r={3} fill={cc} />
      <text x={cx} y={cy + 20} textAnchor="middle" fill={cc} fontSize={20} fontWeight={900}>{wpm || 0}</text>
      <text x={cx} y={cy + 31} textAnchor="middle" fill="#94b8cc" fontSize={8} letterSpacing={2}>WPM</text>
    </svg>
  );
}

// ─── RING ────────────────────────────────────────────────────────────────────
function Ring({ value, total }) {
  const pct    = total > 0 ? Math.min(value / total, 1) : 0;
  const sz     = 100, stroke = 9, r = (sz - stroke) / 2;
  const circ   = 2 * Math.PI * r;
  const dash   = pct * circ;
  const uid    = `dash-rg${Math.round(pct * 100)}`;

  return (
    <div style={{ position: 'relative', width: sz, height: sz, margin: '0 auto' }}>
      <svg width={sz} height={sz}>
        <defs>
          <linearGradient id={uid} x1="0%" y1="0%" x2="100%" y2="100%">
            <stop offset="0%"   stopColor={rogSubtle(Math.max(0, pct - 0.3))} />
            <stop offset="100%" stopColor={rogSubtle(pct)} />
          </linearGradient>
          <filter id={`f-${uid}`}>
            <feGaussianBlur stdDeviation="2" result="b" />
            <feMerge><feMergeNode in="b" /><feMergeNode in="SourceGraphic" /></feMerge>
          </filter>
        </defs>
        <circle cx={sz / 2} cy={sz / 2} r={r} fill="none" stroke="#dbeafe" strokeWidth={stroke} />
        <circle cx={sz / 2} cy={sz / 2} r={r} fill="none" stroke={`url(#${uid})`} strokeWidth={stroke}
          strokeLinecap="round" strokeDasharray={`${dash} ${circ}`}
          transform={`rotate(-90 ${sz / 2} ${sz / 2})`} filter={`url(#f-${uid})`} />
      </svg>
      <div style={{ position: 'absolute', inset: 0, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center' }}>
        <span style={{ color: '#0c2d48', fontSize: 20, fontWeight: 900 }}>{value}</span>
        <span style={{ color: '#64a0c8', fontSize: 10 }}>of {total}</span>
      </div>
    </div>
  );
}

// ─── BAR ─────────────────────────────────────────────────────────────────────
function Bar({ pct, height = 6 }) {
  return (
    <div style={{ background: '#dbeafe', borderRadius: 50, height }}>
      <div style={{
        width: `${Math.min(pct, 1) * 100}%`,
        height: '100%',
        borderRadius: 50,
        background: `linear-gradient(90deg, ${rogSubtle(Math.max(0, pct - 0.4))}, ${rogSubtle(pct)})`,
        transition: 'width 0.5s ease',
      }} />
    </div>
  );
}

// ─── DASHBOARD ───────────────────────────────────────────────────────────────
function Dashboard() {
  const navigate  = useNavigate();
  const { user }  = useAuth();
  const { language, setLanguage, availableLanguages } = useLanguage();

  const [progress,  setProgress]  = useState(null);
  const [practice,  setPractice]  = useState(null);
  const [loading,   setLoading]   = useState(true);

  // Languages shown in toggle (only enabled ones)
  const toggleLangs = availableLanguages
    ? availableLanguages.filter(l => l.enabled).slice(0, 2)
    : [
        { id: 'english', nativeName: 'English' },
        { id: 'punjabi', nativeName: 'ਪੰਜਾਬੀ'  },
      ];

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        const [progressRes, practiceRes] = await Promise.all([
          api.get(`/progress/lessons?language=${language}`),
          api.get(`/practice?language=${language}`),
        ]);
        setProgress(progressRes.data);
        setPractice(practiceRes.data);
      } catch (err) {
        console.error('Dashboard fetch error:', err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [language]);

  // ── Derived stats ──
  const lessonsTotal    = progress?.totalLessons    || 0;
  const lessonsDone     = progress?.completedLessons || 0;
  const challengingKeys = progress?.challengingKeys  || [];
  const avgWpm          = practice?.averageWpm       || 0;
  const avgAccuracy     = practice?.averageAccuracy  || 0;
  const sessionCount    = practice?.totalSessions    || 0;

  const lessonPct  = lessonsTotal > 0 ? lessonsDone / lessonsTotal : 0;
  const accPct     = avgAccuracy / 100;
  const sessPct    = Math.min(sessionCount / 50, 1);

  const username = user?.name || user?.username || 'User';

  return (
    <div style={{
      minHeight: '100vh',
      background: '#e8f4fd',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      padding: '32px 16px',
      fontFamily: "'Segoe UI', sans-serif",
    }}>
      <div style={{
        width: '100%',
        maxWidth: 580,
        background: '#ffffff',
        borderRadius: 20,
        overflow: 'hidden',
        boxShadow: '0 10px 40px rgba(2,132,199,0.12)',
        border: '1px solid #bfdbfe',
      }}>

        {/* ── Navbar ── */}
        <div style={{
          background: '#f0f8fe',
          padding: '13px 24px',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          borderBottom: '1px solid #bfdbfe',
        }}>
          <span style={{ color: '#0284c7', fontWeight: 700, fontSize: 16 }}>🖥 Typing Tutor</span>
          <span style={{ color: '#64a0c8', fontSize: 13 }}>Welcome, {username}!</span>
        </div>

        <div style={{ padding: '20px 20px 24px' }}>

          {/* ── Language Toggle ── */}
          <div style={{
            display: 'flex',
            background: '#dff0fb',
            borderRadius: 50,
            padding: 4,
            width: 'fit-content',
            margin: '0 auto 18px',
            border: '1px solid #bfdbfe',
          }}>
            {toggleLangs.map(({ id, nativeName }) => (
              <button
                key={id}
                onClick={() => setLanguage(id)}
                style={{
                  padding: '7px 22px',
                  borderRadius: 50,
                  border: 'none',
                  cursor: 'pointer',
                  fontWeight: 600,
                  fontSize: 13,
                  transition: 'all 0.25s',
                  background: language === id
                    ? 'linear-gradient(135deg,#0284c7,#38bdf8)'
                    : 'transparent',
                  color: language === id ? '#fff' : '#64a0c8',
                  boxShadow: language === id
                    ? '0 3px 12px rgba(2,132,199,0.3)'
                    : 'none',
                }}
              >
                {nativeName}
              </button>
            ))}
          </div>

          {/* ── Action Buttons ── */}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12, marginBottom: 14 }}>
            <button
              onClick={() => navigate('/learn')}
              style={{
                padding: '22px 20px',
                borderRadius: 16,
                border: 'none',
                background: 'linear-gradient(135deg,#0284c7,#0ea5e9)',
                color: '#fff',
                cursor: 'pointer',
                textAlign: 'left',
                boxShadow: '0 6px 20px rgba(2,132,199,0.25)',
              }}
            >
              <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 8 }}>
                <span style={{ fontSize: 26 }}>📖</span>
                <span style={{ fontWeight: 800, fontSize: 22 }}>Learn</span>
              </div>
              <div style={{ fontSize: 13, color: 'rgba(255,255,255,0.75)', lineHeight: 1.5 }}>
                Follow chapters, master keys step by step
              </div>
            </button>

            <button
              onClick={() => navigate('/practice')}
              style={{
                padding: '22px 20px',
                borderRadius: 16,
                border: '1px solid #bfdbfe',
                background: '#f0f8fe',
                color: '#0c2d48',
                cursor: 'pointer',
                textAlign: 'left',
              }}
            >
              <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 8 }}>
                <span style={{ fontSize: 26 }}>⌨️</span>
                <span style={{ fontWeight: 800, fontSize: 22 }}>Practice</span>
              </div>
              <div style={{ fontSize: 13, color: '#64a0c8', lineHeight: 1.5 }}>
                Free typing drills to build speed
              </div>
            </button>
          </div>

          {/* ── Stat Cards ── */}
          {loading ? (
            <div style={{ textAlign: 'center', padding: '24px 0', color: '#64a0c8', fontSize: 13 }}>
              Loading stats…
            </div>
          ) : (
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 }}>

              {/* Learn stat */}
              <div style={{
                background: '#f0f8fe',
                borderRadius: 13,
                border: '1px solid #bfdbfe',
                padding: '11px 11px',
              }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 5, marginBottom: 10 }}>
                  <span style={{ fontSize: 11 }}>📖</span>
                  <span style={{ color: '#0284c7', fontSize: 10, fontWeight: 700, textTransform: 'uppercase', letterSpacing: 0.8 }}>
                    Learn Progress
                  </span>
                </div>

                <Ring value={lessonsDone} total={lessonsTotal} />

                <div style={{ marginTop: 8, marginBottom: 8 }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
                    <span style={{ color: '#64a0c8', fontSize: 10 }}>Completion</span>
                    <span style={{ color: rogSubtle(lessonPct), fontSize: 10, fontWeight: 700 }}>
                      {Math.round(lessonPct * 100)}%
                    </span>
                  </div>
                  <Bar pct={lessonPct} height={5} />
                </div>

                {challengingKeys.length > 0 && (
                  <>
                    <div style={{ color: '#94b8cc', fontSize: 9, textTransform: 'uppercase', letterSpacing: 0.8, marginBottom: 5 }}>
                      ⚠️ Challenging
                    </div>
                    <div style={{ display: 'flex', gap: 4, flexWrap: 'wrap' }}>
                      {challengingKeys.slice(0, 6).map(k => (
                        <span key={k} style={{
                          background: '#fff7ed',
                          border: '1px solid #fed7aa',
                          color: '#c2640a',
                          borderRadius: 5,
                          padding: '2px 6px',
                          fontSize: 11,
                          fontWeight: 700,
                        }}>{k}</span>
                      ))}
                    </div>
                  </>
                )}
              </div>

              {/* Practice stat */}
              <div style={{
                background: '#f0f8fe',
                borderRadius: 13,
                border: '1px solid #bfdbfe',
                padding: '11px 11px',
              }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 5, marginBottom: 6 }}>
                  <span style={{ fontSize: 11 }}>⌨️</span>
                  <span style={{ color: '#0369a1', fontSize: 10, fontWeight: 700, textTransform: 'uppercase', letterSpacing: 0.8 }}>
                    Practice
                  </span>
                </div>

                <Speedometer wpm={avgWpm} />

                <div style={{ marginTop: 6 }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 3 }}>
                    <span style={{ color: '#64a0c8', fontSize: 10 }}>Accuracy</span>
                    <span style={{ color: rogSubtle(accPct), fontSize: 10, fontWeight: 700 }}>{avgAccuracy}%</span>
                  </div>
                  <Bar pct={accPct} height={4} />
                </div>

                <div style={{ marginTop: 6 }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 3 }}>
                    <span style={{ color: '#64a0c8', fontSize: 10 }}>Sessions</span>
                    <span style={{ color: rogSubtle(sessPct), fontSize: 10, fontWeight: 700 }}>{sessionCount}</span>
                  </div>
                  <Bar pct={sessPct} height={4} />
                </div>
              </div>

            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
